    public function getMoreDoctors($id,$count)
    {    
          $hospital_team=[];
          $user = User::where('id', (int)$id)->with('diseases','specialities','procedures','location','area','services','profile','feedbacks','feedbacks','doc_teams','appointments','roles','question','answers','onlines','speciality','labTest','branches','teams')->first();
           
          if ($user->teams != null) {
                foreach($user->teams as $getdata) {
                $hospital_team[] = User::where('id', $getdata->doctor_id)->with('profile','specialities','location','doc_teams','teams','feedbacks')->first();
                }
              }
           return response()->json($hospital_team);
    }
    public function getResultLocationArea($location)
    {
        // dd($location);
        $location_id=Location::where('slug','like','%'.$location.'%')->pluck('id');
        $areas=Area::where('location_id',$location_id)->select('id','slug','title','location_id')->get();
        return response()->json($areas);
    }
    public function getMoreOtherHospital($id,$top=null)
    {
         $user = User::where('id', $id)->with('location')->first();     
        if($top==null)
        {
         $location_users = User::role('hospital')->whereIn('location_id', [$user->location->id])->with('location')->with('area')->with('diseases')->with('services')->where('id', '!=', $user->id)->limit(1000)->get();
         return response()->json($location_users);
        }
        else{
             $location_users = User::role('hospital')->whereIn('location_id', [$user->location->id])->with('location')->with('area')->orderBy("trending","desc")->where('id', '!=', $user->id)->limit(1000)->get();
             return response()->json($location_users);
        }
         
    }
    public function getSpecialityAndLocation()
    {
        $specialities=Speciality::select('id','title')->get();
        $location=Location::select('id','title')->get();
        return response()->json([$specialities,$location]);
    }
    public function getDiseasesOfUserSpeciality($user,$id)
    {
        $speciality=Speciality::where('id',$id)->select('id')->with('diseases',function($q) use($id){
            return $q->where('speciality_id',$id)->select('id','title','slug','speciality_id')->take(9);
        })->first();
        $diseases=$speciality->diseases;
        if($diseases->isEmpty())
        {
           $diseases=Disease::select('id','title','slug','speciality_id')->take(9)->inRandomOrder()->get(); 
            return response()->json($diseases);
        }
        else
        {
            return response()->json($diseases);
        }

    }
