    public function submitFeedack(Request $request)
    {
        $feedback_submission = Feedback::submitFeedback($request);
        if ($feedback_submission == 'success') {
            return response()->json(
                [
                    'type' => 'success',
                    'message' => trans('Feedback Submitted'),

                ]
            );
        } else {
            return response()->json(
