                    'message' => trans('lang.something_went_wrong'),

                ]
            );
        }
    }

    /**
     * Send Download Application Email
     *
     * @return response
     */
    public function sendDownloadAppEmail(Request $request)
    {
        if (!empty(config('mail.username')) && !empty(config('mail.password'))) {
            $sidebar  = SiteManagement::getMetaValue('sidebar_settings');
            $download_app_link = !empty($sidebar) && !empty($sidebar['download_app_link']) ? $sidebar['download_app_link'] : '#';
            $email_params = array();
            $email_params['download_link'] = $download_app_link;
            $template_data = Helper::getDownloadAppEmailContent();
            Mail::to($request['email'])
                ->send(
                    new GeneralEmailMailable(
                        'general_email_download_application',
                        $template_data,
                        $email_params
                    )
                );
            return response()->json(
                [
                    'type' => 'success',
                    'message' => trans('lang.app_link_sent')
                ]
            );
        } else {
            return response()->json(
                [
                    'type' => 'success',
                    'message' => trans('lang.something_went_wrong')
                ]
            );
        }
    }
    /**
     * Get doctor's appointment slots
     *
     * @param \Illuminate\Http\Request $request request attributes
     *
     * @access public
     *
     * @return \Illuminate\Http\Response
     */
    public function getAppointmentSlots($doctor_id,$user_id)
    {

       $x = 0 ;
       $all_dates = [];
        $today = date("m")."/".date("d")."/".date("Y") ;
        for ( $year = date("Y");$year < date("Y") + 1; $year++ ) {
            for ( $all_datesmonth = date("m");$month < date("m") + 2;$month++ ) {
                for ( $day = date("d");$day <= date("d")+31;$day++ ) {            
                            
                    if ( $x == 30 ) exit() ;
                    $day  = $day++  ;
                    if ( $day > 31 ) {// change this condition depending on the no of days of the current month                
                        $day = 1 ; 
                        $month++ ;
                    }
                    $all_dates[] = date("YYYY-MM-DD", strtotime($year."-".$month."-".$day));
                    $x++ ;
                     
                }
            }
        }

        // dd($all_dates);
        date_default_timezone_set("Asia/Karachi");
        $a_days = array_map('strtolower', $request['days']);
        $a_dates = $request['dates'];
        $json = array();
        $list = array();
        $lists = array();
        foreach ($a_dates as $index => $a_date) {
            $list = array();
            
            $hospital = Team::select('slots')->where('doctor_id', $doctor_id)->where('user_id', $user_id)->first();
           
            // dd(5);
            if (!empty($hospital)) {
                $requested_date = Carbon::create($a_date);

                $date = new Carbon();
                $today = $date->now();
                $slots = json_decode($hospital->slots, true);
                $requested_day_slots = !empty($slots[$a_days[$index]]) ? $slots[$a_days[$index]]['slots'] : array();

                if (!empty($requested_day_slots)) {
                    $counter = 0;
                    foreach ($requested_day_slots as $key => $slot) {
                        $time = explode('-', $key);
                        $list[$counter]['start_time'] = $time[0];
                        $bocked_appointments = DB::table('appointments')->where('appointment_time', $time[0])->where('appointment_date', $a_date)->count();
                        $requested_date->hour   = date("H:i", strtotime($time[0]));
                        if ($requested_date->lessThan($today)) {
                            $list[$counter]['space'] = 0;
                        } else if ($bocked_appointments > 0) {
                            $list[$counter]['space'] = $slot['space'] - $bocked_appointments;
                        } else {
                            $list[$counter]['space'] = (int)($slot['space']);
                        }
                        $counter++;
                    }
                }
                $lists[$a_date] = $list;
            }
        }
        $json['type'] = 'success';
        $json['slots'] = $lists;
        return json_encode($json);

    }

