    public function getNextDoctor(Request $request) {
    $speciality = $request->query('speciality');
    $city = $request->query('city');
    // Check if the city is "pakistan"
    if (strtolower($city) === 'pakistan') {
        $selected_speciality = Speciality::with('users')->where('slug', str_replace('-in-pakistan','',$speciality))->first();
        if (!empty($selected_speciality->users)) {
            $users_ids = $selected_speciality->users->pluck('id');
            $users =  User::whereIn('id',$users_ids)->with('specialities')->with('location')->with('profile')->with('feedbacks')->with('doc_teams')->with('teams')->with('appointments')->with('roles')->with("onlines")->paginate(10);
            $user_ids = $users->pluck('id')->toArray();
            $doc_hospitals = Team::whereIn('doctor_id',$user_ids)->pluck('user_id')->toArray();
            $hospitals = User::whereIn('id',$doc_hospitals)->role('hospital')->orderBy("trending","desc")->with('profile','location','area','teams')->get();
            return response()->json([
                'users' => $users->items(),
                'hospitals' => $hospitals
            ]);
        } else {
            return response()->json(['message' => 'No users  found for the given speciality in Pakistan.']);
        }
    } else {
       
        $speciality_id = Speciality::where('slug', $speciality)->first()->id;
        $city_id = Location::where('slug', $city)->first()->id;

        $specialityUsers = DB::table('user_speciality')
            ->where('speciality_id', $speciality_id)
            ->pluck('user_id')
            ->toArray();

        $users = User::whereIn('id', $specialityUsers)
            ->where('location_id', $city_id)
            ->select('users.id', 'users.first_name', 'users.last_name', 'users.location_id', 'users.slug')
            ->with('location', 'doc_teams', 'teams', 'onlines', 'roles', 'feedbacks')
            ->with(['profile' => function ($q) {
                $q->select('user_id', 'avatar', 'banner', 'address', 'longitude', 'latitude', 'votes', 'available_days', 'working_time', 'created_at', 'updated_at', 'total_experience', 'description', 'experiences', 'memberships', 'educations', 'awards', 'gender', 'sub_heading', 'wait_time', 'short_desc');
            }])
            ->with(['specialities' => function ($q) {
                $q->select('title', 'slug', 'image');
            }])
            ->paginate(10);

        if ($users->count() > 0) {
            $user_ids = $users->pluck('id')->toArray();

            $doc_hospitals = Team::whereIn('doctor_id', $user_ids)->pluck('user_id')->toArray();

            $hospitals = User::whereIn('id', $doc_hospitals)
                ->role('hospital')
                ->orderBy('trending', 'desc')
                ->with('profile', 'location', 'area', 'teams')
                ->get();

            return response()->json([
                'users' => $users->items(),
                'hospitals' => $hospitals,
            ]);
        } else {
            return response()->json(['message' => 'No users  found for the given speciality and city.']);
        }
    }
}

