    public function treatmentData(Request $request)
    {
        $service = request()->route()->parameters['slug'];
            $service_title=ucfirst($service); 

            $area = []; 
            $page_title = 'Find a doctor by '.$service_title.' In Pakistan - Doctorfindy';
         $meta_title = 'Find a doctor by '.$service_title.' In Pakistan - Doctorfindy';
         $meta_description = 'Choose the right doctor, surgeon or physician according to the '.$service_title.', and book an online appointment with the best doctor in Pakistan.'; 
         if($service != null){
            $speciality_id = Service::where('slug',$service)->pluck('speciality_id')->first();
       
            $service=!empty($service) ? Service::where('slug',$service)->select('id','slug','title','speciality_id','description')->with('speciality',function ($q){
                return $q->select('id','title','slug');
            })->with('users')->with('faqsAssign')->first() : '';
             

            $user_ids = DB::table('user_speciality')->where('speciality_id',$speciality_id)->limit(15)->pluck('user_id')->toArray();
             $users = User::role('doctor')->whereIn('id',$user_ids)->select('id','first_name','last_name','location_id','slug')->with('roles')->with('location','doc_teams','teams','onlines','feedbacks')->with('profile',function ($query){
                  return $query->select('user_id','avatar','banner','address','longitude','latitude','votes','available_days','working_time','created_at','updated_at','total_experience','description','experiences','memberships','educations','awards','gender','sub_heading','wait_time','short_desc');
             })->with('specialities')->limit(15)->get();


            $user_ids = $users->pluck('id')->toArray();

            $meta_type = 'doctor';
           

            $total_count = $users->count();
      
            $doc_hospitals =Team::whereIn('doctor_id',$user_ids)->pluck('user_id')->toArray();
            
            $script_data_doctor = [];
            $script_data_faqs = [];
            $script_data_breadCrumbs = [];
        
            $location='';

            $disease= [];
            $speciality = [];
                
           
            $tests = [];
            $doctors = [];
            // dd($doctors[0]);
            /*Hospital*/
            $hospitals = User::whereIn('id',$doc_hospitals)->role('hospital')->orderBy("trending","desc")->with('location')->with('profile',function ($query){
                  return $query->select('user_id','avatar','banner','address','longitude','latitude','votes','available_days','working_time','created_at','updated_at','total_experience','description','experiences','memberships','educations','awards','gender','sub_heading','wait_time','short_desc');
             })->select('id','first_name','last_name','location_id','slug')->get();
            
            /*Laboratory*/
            $laboratories = User::role('laboratory')->with('location')->with('profile',function ($query){
                  return $query->select('user_id','avatar','banner','address','longitude','latitude','votes','available_days','working_time','created_at','updated_at','total_experience','description','experiences','memberships','educations','awards','gender','sub_heading','wait_time','short_desc');
             })->select('id','first_name','last_name','location_id','slug')->limit(6)->get();
            /*Specialities*/
            $specialities = Speciality::select('id','title','slug','image')->where('top', '1')->orderBy("created_at","asc")->limit(8)->get();
            /*Diseases*/
            $diseases = Disease::select('id','title', 'slug','flag')->latest()->limit(4)->get();
            /*Services*/
