     public function doctorsDataLocationAreaFilters(Request $request,$location,$area,$video,$today,$experienced,$fee,$male,$female,$highest_rated,$time_slot,$filter_from,$filter_to)
    {

        $location = $location;
        $area = $area;
        $video = $video;
        $today = $today;
        $experienced = $experienced;
        $fee = $fee;
        $male= $male;
        $female = $female;
        $highest_rated = $highest_rated;
        $time_slot=$time_slot;
        $filter_from=$filter_from;
        $filter_to=$filter_to;

        if($location != null)
        {
            $location_data=Location::where('slug',$location)->select('id','title','slug')->first();
             $user_ids=User::role('doctor')->where('location_id', $location_data->id)->whereHas('profile')->whereHas('doc_teams')->latest()->limit(40)->pluck('id')->toArray();
             if($time_slot !== 'false')
             {
                $user_ids=Team::whereIn('doctor_id',$user_ids)->whereJsonContains('slots', [$filter_from,$filter_to])->latest()->pluck('doctor_id');
             }
              
                if($area !== 'null')
                {
                   $area_title=Area::where('slug',$area)->select('id','slug','title')->first();
                 $area_id=$area_title->id;

