    public function cityDoctors(Request $request)
    {
        $locationSlug = request()->route()->parameters['location']; 
        $area=[]; 
        $location=Location::where('slug',$locationSlug)->first();
        
        $page_title = 'Find and Book Best doctors in '.$location->title.' - Doctorfindy';
        $meta_title = 'Find and Book Best doctors in '.$location->title.' - Doctorfindy';
        $meta_description = 'Looking for best doctors in '.$location->title.'? Doctorfindy will help you find and book any doctor appointment online at reasonable price.';
        $faq = Faq::with('faqAssign')->get();
        $faqs = FaqAssign::with('faqs')->get();
       
        $usersData = User::role('doctor')->with('roles')->with('diseases','specialities','location','feedbacks','doc_teams','teams','appointments','onlines','roles','speciality')->where('location_id', $location->id)->with('profile',function ($q){
                return $q->select('user_id','avatar','banner','address','longitude','latitude','votes','available_days','working_time','created_at','updated_at','total_experience','description','experiences','memberships','educations','awards','gender','sub_heading','wait_time','short_desc');
            })->paginate(15);

            $total_count = $usersData->total();
            $users = $usersData->items();
            $userCollection = collect($users);
            
            $user_ids = $userCollection->pluck('id')->toArray();

            $meta_type = 'doctor';
      
            $doc_hospitals =Team::whereIn('doctor_id',$user_ids)->pluck('user_id')->toArray();

            $script_data_doctor = [];
            $script_data_faqs = [];
            $script_data_breadCrumbs = [];


            $disease= [];
            $service= [];
            $speciality = [];

            $tests = [];
            $doctors = User::role('doctor')
            ->with('location')->with('profile',function ($q){
                return $q->select('user_id','avatar','banner','address','longitude','latitude','votes','available_days','working_time','created_at','updated_at','total_experience','description','experiences','memberships','educations','awards','gender','sub_heading','wait_time','short_desc');
            })->with('specialities',function ($q){
                return $q->take(5);
            })->limit(4)->get();
          
            /*Hospital*/
            $hospitals = User::whereIn('id',$doc_hospitals)->role('hospital')->orderBy("trending","desc")->with('location','area')->with('profile',function($q){
                return $q->select('user_id','avatar','banner','address','longitude','latitude','votes','available_days','working_time','created_at','updated_at','total_experience','description','experiences','memberships','educations','awards','gender','sub_heading','wait_time','short_desc','hospital_services');
            })->with('teams',function($q){
                return $q->take(10);
            })->get();
          
            /*Laboratory*/
            $laboratories = User::role('laboratory')->with('location','area')->with('profile',function ($q){
                return $q->select('user_id','avatar','banner','address','longitude','latitude','votes','available_days','working_time','created_at','updated_at','faqs','total_experience','description');
            })->limit(6)->get();
            /*Specialities*/
            $specialities = Speciality::select('id','title','slug','image')->where('top', '1')->orderBy("created_at","asc")->limit(8)->get();
            /*Diseases*/
            $diseases = Disease::select('id','title', 'slug','flag')->latest()->limit(4)->get();
            /*Services*/
            $services = Service::select('id','title', 'slug','image')->latest()->limit(4)->get();
            /*Locations*/
            $cities = Location::where('top', '1')->orderBy("created_at","asc")->limit(6)->get();
            $cities_pakistan = Location::inRandomOrder()->limit(8)->get();

            $segments = \Request::segments();
            $type = $metadata->type ?? $meta_type;
            $user = User::where('id', Auth::id() ? Auth::id() : '')->with('profile')->with('roles')->first();
            $logged_user = $user ? $user : [];
            
            $spclty = null;
            $servic = null;
           
            
            $meta_values = ['header_service','show_headertabs','topbar_settings','general_settings','download_app_sec','home_slider','socials','footer_settings','subscribe_now_sec'];
            $managements = SiteManagement::whereIn('meta_key',$meta_values)->get();
            if (!empty($users)) {


                return view(
                    'front-end.search-results.cityAreaDoctorsList',
                    compact(
                        'users',
                        'type',
                        'area',
                        'location',
                        'service',
                        'disease',
                        'services',
                        'speciality',
                        'specialities',
                        'diseases',
                        'cities',
                        'cities_pakistan',
                        'laboratories',
                        'faq',
                        'faqs',
                        'segments',
                        'doctors',
                        'hospitals',
                        'managements',
                        'logged_user',
                        'tests',
                        'page_title',
                        'meta_title',
                        'meta_description',
                        'total_count'
                    )
                );
            } else {
            abort(404);
            }

    }
